import React, { useState } from 'react';
import Wavify from 'react-wavify';
import '../styles/Home.css';

function Home() {
  const [isUserSpeaking, setIsUserSpeaking] = useState(false);
  const [isCoachSpeaking, setIsCoachSpeaking] = useState(false);

  const handleUserSpeak = () => {
    setIsUserSpeaking(true);

    // Simulate user speaking for 3 seconds, then coach responds after 5 seconds
    setTimeout(() => {
      setIsUserSpeaking(false);
      setIsCoachSpeaking(true);

      // Simulate coach speaking duration
      setTimeout(() => {
        setIsCoachSpeaking(false);
      }, 5000); // Coach speaks for 5 seconds
    }, 3000); // User speaks for 3 seconds
  };

  return (
    <div className="home-container">
      <div className="animated-background"></div>
      <h1 className="home-heading patrick-hand-regular">26Coach</h1>
      <h3 className="home-subheading patrick-hand-regular">THE MARATHON COACH THAT LIVES IN YOUR AIRPODS</h3>
      <div className="cta-container">
        <button 
          onClick={handleUserSpeak} 
          className={`cta-button ${isUserSpeaking ? 'pulse' : ''}`}
        >
          Speak to 26Coach
        </button>
      </div>

      <div className="wave-container">
        {isCoachSpeaking && (
          <Wavify 
            fill="#DE7C7D"
            paused={false}
            options={{
              height: 30,
              amplitude: 25,
              speed: 0.3,
              points: 4,
            }}
          />
        )}
      </div>
    </div>
  );
}

export default Home;
